const topic = $.input.topic || 'AI automation';
const query = 'Latest insights and research about ' + topic + ' with expert analysis and data';
return { query, topic };

const response = $.steps.exaSearch.response || {};
const results = response.data?.results || response.results || [];
let research = '';
results.forEach(function(r, i) {
  research += '=== SOURCE ' + (i + 1) + ' ===\n';
  research += 'Title: ' + (r.title || 'Untitled') + '\n';
  research += 'URL: ' + (r.url || '') + '\n';
  research += 'Content: ' + (r.text || '').slice(0, 2000) + '\n\n';
});
return { research: research, sourceCount: results.length, topic: $.input.topic };

const data = $.steps.compileResearch.output;

let prompt = 'You are an expert SEO content writer. Create a comprehensive, SEO-optimized blog article based on the research provided.

';
prompt += 'TOPIC: ' + data.topic + '
';
prompt += 'SOURCES RESEARCHED: ' + data.sourceCount + '

';
prompt += 'RESEARCH CONTENT:
' + data.research + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Write a 600-800 word blog article with proper H1, H2 structure
';
prompt += '- Include a compelling meta description (under 160 chars)
';
prompt += '- Use data and insights from the research sources
';
prompt += '- Keep tone professional but engaging
';
prompt += '- Include a conclusion with actionable takeaways

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "title": "SEO-optimized article title",
';
prompt += '  "metaDescription": "under 160 char meta description",
';
prompt += '  "article": "full HTML article with h1, h2, p tags",
';
prompt += '  "summary": "2-3 sentence summary",
';
prompt += '  "keywords": ["keyword1", "keyword2", "keyword3"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.topic, metaDescription: '', article: raw, summary: raw.slice(0, 200), keywords: [] }; }

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'New Blog Article Published', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'New Article') + '*' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.summary || '').slice(0, 1500) } });
blocks.push({ type: 'divider' });
if (ai.keywords && ai.keywords.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Keywords:* ' + ai.keywords.join(', ') } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Sent via Gmail | Logged in Notion | Powered by Exa + Claude AI' }] });
const fallbackText = 'New blog article: ' + (ai.title || $.input.topic);
return { blocks, fallbackText };
